        .marquee-wrapper {
                position: absolute;
                width: 100%;
                background-color: transparent;
                color: white;
                overflow: hidden;
                white-space: nowrap;
                top: 127px;
                z-index: 1000;
                font-size: 16px;
                padding: 3px 0;
        }
        .marquee {
            display: inline-block;
            animation: marquee 20s linear infinite;
        }
        @media (max-width: 1199px){
            .marquee-wrapper {
                top: 72px;
                color: #000;
            }    
        }
        @media (max-width: 767px){
            .marquee-wrapper {
                top: 157px;
                background-color: #fff;
                padding: 10px 0;
            }    
        }
        @keyframes marquee {
            0% {
                transform: translateX(100%);
            }
            100% {
                transform: translateX(-100%);
            }
        }

        .js-sticky-header.is-active + #header .marquee-wrapper{
            position: fixed;
            top: 85px;
            background-color: rgba(0,122,161,.85);
